import React from 'react';
import { Link } from 'react-router-dom';
import { AppBar, Toolbar, Button, Box } from '@mui/material';

const Navbar = () => {
  // // Inline sx prop styles for MUI components
  // const navItemSx = {
  //   flexGrow: 1,
  //   color: 'inherit',
  //   textDecoration: 'none',
  //   '&:hover': {
  //     textDecoration: 'underline',
  //   },
  //   display: 'block', // make sure the link takes the full height of the Toolbar
  //   marginRight: 4, // Add spacing to the right of each nav item
  // };

  const handleDownloadClick = () => {
    window.open('https://huggingface.co/hyonbokan/BGPStream13-10k-cutoff-1024-max-2048', '_blank');
  };

  return (
    <AppBar position="static" sx={{ backgroundColor: '#2D3748', color: 'white' }}>
      <Toolbar sx={{ justifyContent: 'space-between' }}>
        <Box sx={{ display: 'flex', alignItems: 'center' }}>
          {/* Apply margin to each Link instead of flexGrow */}
          <Link to="/" sx={{ color: 'inherit', textDecoration: 'none', margin: '0 20px' }}>
            Home
          </Link>
          <Link to="/dataset" sx={{ color: 'inherit', textDecoration: 'none', margin: '0 20px' }}>
            Dataset
          </Link>
          <Link to="/bgp_llama" sx={{ color: 'inherit', textDecoration: 'none', margin: '0 20px' }}>
            BGP-LLaMA
          </Link>
        </Box>
        <Button color="primary" variant="contained" onClick={handleDownloadClick}>
          Download models
        </Button>
      </Toolbar>
    </AppBar>
  );
};

export default Navbar;
